const fs = require("fs");
const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  ImageRun, AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, Footer
} = require("docx");

const CW = 9360; // content width DXA (US Letter, 1" margins)

// ---------- helpers ----------
const P = (text, opts = {}) => new Paragraph({
  alignment: opts.align || AlignmentType.JUSTIFIED,
  spacing: { after: opts.after ?? 140, line: 276 },
  children: [new TextRun({ text, bold: opts.bold, italics: opts.italics, size: opts.size || 22 })],
});
const H1 = (t) => new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun(t)] });
const H2 = (t) => new Paragraph({ heading: HeadingLevel.HEADING_2, children: [new TextRun(t)] });
const bullet = (t) => new Paragraph({ numbering: { reference: "b", level: 0 },
  spacing: { after: 80 }, children: [new TextRun({ text: t, size: 22 })] });

function fig(file, caption, wPx, hPx) {
  const items = [];
  items.push(new Paragraph({
    alignment: AlignmentType.CENTER, spacing: { before: 120, after: 40 },
    children: [new ImageRun({ type: "png", data: fs.readFileSync(file),
      transformation: { width: wPx, height: hPx },
      altText: { title: caption, description: caption, name: file } })],
  }));
  items.push(new Paragraph({ alignment: AlignmentType.CENTER, spacing: { after: 180 },
    children: [new TextRun({ text: caption, italics: true, size: 19 })] }));
  return items;
}

const bd = { style: BorderStyle.SINGLE, size: 1, color: "AAAAAA" };
const borders = { top: bd, bottom: bd, left: bd, right: bd };
function cell(text, w, head) {
  return new TableCell({ borders, width: { size: w, type: WidthType.DXA },
    shading: head ? { fill: "D5E8F0", type: ShadingType.CLEAR } : undefined,
    margins: { top: 60, bottom: 60, left: 100, right: 100 },
    children: [new Paragraph({ children: [new TextRun({ text, bold: !!head, size: 20 })] })] });
}
function table(widths, rows) {
  return new Table({ width: { size: CW, type: WidthType.DXA }, columnWidths: widths,
    rows: rows.map((r, ri) => new TableRow({ children: r.map((c, ci) => cell(String(c), widths[ci], ri === 0)) })) });
}
const capt = (t) => new Paragraph({ spacing: { before: 60, after: 120 },
  children: [new TextRun({ text: t, italics: true, size: 19 })] });

// ---------- content ----------
const C = [];
// Title
C.push(new Paragraph({ alignment: AlignmentType.CENTER, spacing: { after: 120 },
  children: [new TextRun({ bold: true, size: 30,
    text: "An Interpretable and Uncertainty-Aware Framework for Lithium-Ion Battery State-of-Health and Remaining-Useful-Life Prognostics on Public Datasets" })] }));
C.push(new Paragraph({ alignment: AlignmentType.CENTER, spacing: { after: 40 },
  children: [new TextRun({ size: 22, text: "Peixun Wang, Peijun Zhou, Shu Hong, Zhuohua Quan *" })] }));
C.push(new Paragraph({ alignment: AlignmentType.CENTER, spacing: { after: 40 },
  children: [new TextRun({ italics: true, size: 20, text: "Tianjin Lishen Battery Co., Ltd., Tianjin, China" })] }));
C.push(new Paragraph({ alignment: AlignmentType.CENTER, spacing: { after: 40 },
  children: [new TextRun({ size: 19, text: "* Correspondence: quanzhuohua@lishen.com.cn" })] }));
C.push(new Paragraph({ alignment: AlignmentType.CENTER, spacing: { after: 200 },
  children: [new TextRun({ size: 19, text: "ORCID: P. Wang, 0009-0003-4240-9998 (other authors' ORCID iDs to be added at submission)" })] }));

C.push(H1("Abstract"));
C.push(P("Reliable lithium-ion battery state-of-health (SOH) and remaining-useful-life (RUL) estimation underpins the safe, economical operation of electric vehicles and grid storage, yet data-driven prognostics still struggle with three obstacles: limited interpretability, the absence of calibrated uncertainty, and brittleness under distribution shift. We present a framework that addresses these together and evaluate it under strict cell-level, batch-aware protocols on public data spanning two chemistries (the Severson lithium-iron-phosphate corpus and the NASA lithium-cobalt-oxide set), with a third dataset (CALCE LCO) used for a direct transfer test. On a shared set of charge and discharge curve features, including incremental-capacity (IC) descriptors, ridge, support-vector and random-forest regressors are combined with genetic-programming symbolic regression for an interpretable degradation law and split-conformal prediction for empirically calibrated intervals."));
C.push(P("On unseen Severson cells, SOH is estimated at RMSPE 1.26 ± 0.26% with conformal intervals reaching the nominal 90% coverage, and a single IC-peak feature carries most of the model importance; a partial voltage window of only 10 to 20% of the curve retains near-full accuracy, supporting on-board use. A deployable RUL pipeline that uses an out-of-sample SOH estimate (no capacity label at inference) reaches R² = 0.82. Rigorous evaluation also exposes failure modes that single-split studies hide: uncertainty-based active learning does not reliably beat random sampling, and naive cross-batch transfer collapses to negative R²."));
C.push(P("Generalisation is therefore bounded and quantified. A second dataset (NASA, leave-one-cell-out) remains accurate; under streaming cross-batch drift, adaptive conformal recalibration restores near-nominal coverage where static conformal intervals fail; and a direct cross-system test (the LFP and LCO datasets differ in both chemistry and charging protocol) shows that a frozen model collapses while re-fitting the same pipeline recovers, from as little as one labelled target cell for point accuracy, although reliable conformal coverage remains small-calibration-limited and requires additional target calibration cells. This indicates that the re-fitting protocol, rather than a frozen trained model, can be re-targeted across systems with a small labelled target set, while the diagnostics map where such models fail."));
C.push(P("Keywords: lithium-ion battery; state of health; remaining useful life; incremental capacity; active learning; symbolic regression; conformal prediction; adaptive conformal prediction; distribution shift; uncertainty quantification.", { italics: true }));

C.push(H1("1. Introduction"));
C.push(P("Lithium-ion batteries power electric vehicles, consumer electronics and grid-scale storage, and their safe, economical use depends on knowing two quantities in real time: how healthy a cell is, expressed as its SOH, and how much longer it will function, expressed as its RUL. Neither can be measured directly, so models that infer health from observable charge and discharge signals have become the dominant approach. The release of large public cycling datasets, notably the 124-cell fast-charging corpus of Severson et al. [1] and the NASA PCoE ageing set, has accelerated this work and made reproducible benchmarking possible without any in-house experiments [2,3]."));
C.push(P("Three obstacles nonetheless recur. The first is data cost: building a model conventionally requires cycling many cells to end-of-life, which takes months. The second is opacity: the most accurate models are typically black boxes that offer little physical insight and are hard to certify [4]. The third is the absence of calibrated uncertainty: most models report a single number, yet a battery-management system (BMS) making safety- and warranty-critical decisions needs a trustworthy bound on each prediction."));
C.push(P("A deployable prognostic model must be interpretable and uncertainty-aware, and it must be evaluated rigorously enough to reveal where it fails. We therefore study a framework (Figure 1) built on a shared, physically grounded feature representation: feature-based regression models for SOH and RUL, symbolic regression to distil an interpretable closed-form degradation law, and split-conformal prediction to provide empirically calibrated intervals. We additionally test whether uncertainty-based active learning improves labelling efficiency. Throughout, we use cell-level and batch-aware evaluation and report results across two chemistries, so that apparent accuracy is not inflated by optimistic data splitting."));
C.push(P("The central research question of this study is: how can battery SOH and RUL prediction remain interpretable and carry calibrated uncertainty when the data exhibit distribution shift across manufacturing batches and chemistries? Concretely, we test the hypothesis that a shared curve-based feature representation can support accurate SOH and RUL prediction, interpretable degradation-law discovery, and empirically calibrated uncertainty on public cell-level splits, and we ask whether these properties persist under cross-batch evaluation and second-dataset re-application across chemistries. Our contributions are fourfold. (C1) We present a framework that couples interpretable feature-based SOH and RUL regression with symbolic-regression law discovery and split-conformal uncertainty, evaluated under cell-level and batch-aware protocols. (C2) We report a systematic charge and discharge curve feature study, including IC analysis; we show that a single IC peak feature accounts for most of the SOH model importance, and we confirm, under strict cell-level protocols and tied explicitly to the IC-peak mechanism, recent reports that a partial voltage window spanning the phase-transition plateau retains near-full SOH accuracy [5,6,7]. (C3) We provide empirically calibrated conformal prediction intervals for both SOH and RUL, and show that adaptive conformal inference maintains near-nominal coverage under streaming cross-batch drift, where static conformal collapses. (C4) Through multi-seed and batch-aware evaluation, we document and diagnose two failure modes that single-split studies can obscure: the active-learning failure, which we trace to pool homogeneity rather than to a model-specific uncertainty defect, and the cross-batch collapse, which we show is not explained by input-distribution drift alone. A second public dataset further confirms that the same feature-extraction and model-selection protocol remains effective when re-applied to NASA under leave-one-cell-out validation. Finally, a direct LFP-to-LCO transfer test on a third dataset delineates the generalisation boundary: a frozen model does not cross a combined chemistry-and-protocol shift, but the re-fitted pipeline does, with a small and quantified labelling budget."));
fig("fig1_framework.png", "Figure 1. Framework overview, separating the deployable pipeline from the diagnostic modules. The main predictive pipeline (solid path) runs curve features to SOH/RUL models to split-conformal prediction intervals, under an explicit evaluation-protocol layer (cell-level splits, batch-aware transfer, multi-seed reporting, LOCO), with real-data thumbnails (capacity-fade trajectories, an IC curve, a prediction interval drawn to scale). The diagnostic modules (dashed branch) are not part of the deployed pipeline: active learning, symbolic-regression law discovery, cross-batch MMD analysis, adaptive conformal inference, and the LFP-to-LCO transfer test. Outputs are a point prediction, a calibrated interval, and a failure-mode map.", 620, 305).forEach(x => C.push(x));

C.push(H1("2. Related Work"));
C.push(P("Data-driven battery health modelling spans linear and regularised regression, support-vector machines, Gaussian processes, random forests and deep networks; comprehensive reviews survey this rapidly growing field [2], and recent studies estimate capacity or health from engineered charge and discharge curve features, from impedance spectra, and from voltage-relaxation signals [8,9,10]. Quantifying predictive uncertainty, in turn, requires distinguishing aleatoric from epistemic sources [11]. The three studies most directly related to ours typify the prevailing methodology. Roman et al. [12] build a machine-learning pipeline for SOH on 179 cells; they engineer thirty features from charge voltage and current segments with automatic feature selection and adversarial augmentation, report confidence bounds, and reach an RMSPE as low as 0.45%. Wu et al. [13] extract a small set of charging-curve health features and apply ridge regression to joint SOH and RUL estimation. Li et al. [14] construct health indicators by convolving the discharge voltage, reduce dimensionality with principal component analysis (PCA), and optimise a support-vector regression (SVR) model with an improved swarm algorithm, validating on the NASA set. Our framework shares the charge and discharge feature philosophy of these works, but it differs in two ways: it unifies interpretability and calibrated uncertainty in one system, treating sample-efficiency and cross-batch generalisation as questions to be tested rather than assumed, and it is validated across two chemistries."));
C.push(P("Incremental-capacity analysis differentiates capacity with respect to voltage to expose phase-transition peaks whose height, position and area track ageing [15,16,17]. It is a well-established and physically interpretable health indicator, and on-board variants have been combined with support-vector regression for SOH estimation [16]; its relative importance within the present framework is evaluated in Section 5.1. A rapidly maturing line of work estimates SOH from partial voltage segments rather than full cycles: Javaid et al. [5] used mutual information to select discharge-segment ranges for a neural network, Ren et al. [6] built an MI-guided pipeline that reaches roughly 1.3% RMSE from charging segments as narrow as 0.05 V across three chemistries, and Jelovic et al. [7] extracted partial-segment IC features automatically via proper orthogonal decomposition. These studies establish that partial segments suffice and that segment selection can be automated; none of them, however, provides calibrated prediction intervals, batch-aware generalisation tests, or RUL, which is where the present framework differs. Severson et al. [1] showed that the log-variance of the cycle-10-to-100 discharge-curve difference, var(ΔQ(V)), predicts cycle life before noticeable capacity fade, and Attia et al. [18] extended this idea to closed-loop charging optimisation. Our symbolic-regression module recovers the same relationship automatically rather than by manual design. Uncertainty-driven active learning [19], genetic-programming symbolic regression [20,21,22] and distribution-free conformal prediction [23,24] are each individually mature, yet their joint application to battery prognostics, and the comparison of their behaviour across homogeneous and heterogeneous data, has received little attention."));

C.push(table([1560, 1760, 1040, 1600, 1600, 1800], [
  ["Study", "Dataset", "Task", "Model / features", "Calibrated uncertainty", "Cross-batch / 2nd dataset"],
  ["Roman et al.", "MATR + others (179)", "SOH", "RF/DNN, 30 feat.", "Yes (intervals)", "No"],
  ["Wu et al.", "Two public sets", "SOH+RUL", "Ridge, 3 feat.", "No", "No"],
  ["Li et al.", "NASA + lab", "SOH", "SVR, HI + PCA", "No", "No"],
  ["Partial-segment studies (2024-2026)", "Severson/NASA/CALCE/Oxford", "SOH (partial segments)", "MI / POD selection", "No", "No"],
  ["This work", "Severson + NASA", "SOH+RUL", "Explicit formula + importances", "Yes (conformal + ACI)", "Yes (cell/batch-aware)"],
]));
C.push(capt("Table 1. Positioning relative to representative SOH/RUL studies. Among the representative studies compared here, none evaluates interpretability, calibrated uncertainty, and batch-aware or second-dataset performance for both SOH and RUL within a single protocol."));
C.push(H1("3. Datasets and Definitions"));
C.push(H2("3.1 Datasets"));
C.push(P("Three public datasets are used (Table 2): two primary corpora spanning two chemistries, used throughout, and a third (CALCE CS2) used only for the direct cross-system transfer test of Section 5.9. The first is the extended MATR corpus derived from the fast-charging studies of Severson et al. [1] and Attia et al. [18] (LFP/graphite, 1.1 Ah nominal). The original Severson et al. dataset reports 124 commercial cells; the publicly released MATR corpus comprises four batches (2017-05-12, 2017-06-30, 2018-04-12 and 2019-01-24), from which we obtained 182 usable cells after parsing the raw MATLAB v7.3/HDF5 structures and discarding cells with missing or corrupt records. Each cell provides per-cycle summary signals (discharge capacity, internal resistance, charge time and temperature) and linearly-interpolated discharge capacity-voltage curves Q(V) on a common 1000-point voltage grid. We used 140 cells with internal-resistance records (batches 1 to 3) for per-cycle SOH modelling, and 128 cells that reached the end-of-life threshold for RUL. The second dataset, from the NASA Prognostics Center of Excellence (PCoE; [25]; LCO/graphite 18650, 2 Ah nominal), provides four cells (B0005, B0006, B0007 and B0018) with per-cycle voltage, current, temperature, time and measured discharge capacity. Its different chemistry and small cell count make it a demanding second-dataset test. For the direct cross-chemistry transfer experiment (Section 5.9) we additionally use the CALCE CS2 dataset [26]: six prismatic LCO/graphite cells (~1.1 Ah nominal) cycled to end-of-life under constant-current charge and discharge, which we parsed to 4,808 per-cycle discharge curves spanning 2.7 to 4.2 V. Its clean constant-current curves and longer per-cell cycling make it better suited than the four NASA cells to the cell-level, few-shot and conformal evaluation that a transfer test requires."));
C.push(table([2160, 2280, 2160, 2760], [
  ["Property", "Severson (MATR)", "NASA PCoE", "CALCE CS2"],
  ["Chemistry", "LFP/graphite", "LCO/graphite (18650)", "LCO/graphite (prismatic)"],
  ["Nominal capacity", "1.1 Ah", "2 Ah", "~1.1 Ah"],
  ["Batches / cells (raw)", "4 batches; 124 in Severson et al.", "4 cells", "6 cells"],
  ["Usable cells (parsed)", "182", "4", "6"],
  ["Cells for SOH", "140 (batches 1-3, with IR)", "4", "6 (no IR channel)"],
  ["Cells reaching EOL (RUL)", "128", "n/a", "n/a"],
  ["SOH cycle-level samples", "16,800", "625", "4,808"],
  ["RUL cycle-level samples", "15,046", "n/a", "n/a"],
  ["Charge/discharge protocol", "fast-charging", "constant-current", "constant-current"],
  ["Split unit", "cell-level", "leave-one-cell-out", "cell-level (transfer)"],
  ["Per-cycle signals", "Q(V), IR, charge time, T", "V, I, T, capacity", "V, I, Q"],
  ["Role in this study", "primary: SOH, RUL, diagnostics", "second-dataset LOCO", "LFP-to-LCO transfer / few-shot / calibration"],
]));
C.push(capt("Table 2. Summary of the three public datasets and the cell and sample counts used in each task. Severson (MATR) is the primary corpus; NASA is the second-dataset leave-one-cell-out test; CALCE CS2 is used only for the direct LFP-to-LCO transfer experiment (Section 5.9). The original Severson et al. study reports 124 cells; the released MATR corpus yields 182 usable cells after parsing, of which 140 (batches 1 to 3, which carry internal-resistance records) were used for SOH and 128 (those reaching end-of-life) for RUL. CALCE has no internal-resistance channel, so its SOH features are curve-based only."));
C.push(H2("3.2 SOH, EOL and RUL definitions"));
C.push(P("State of health is defined relative to the cell's initial capacity, SOH(k) = Qd(k)/Q0, where Q0 is the median discharge capacity of the first ten valid cycles. End-of-life (EOL) is the cycle at which capacity first reaches 80% of nominal capacity (0.88 Ah for the LFP cells). The remaining useful life at cycle k is RUL(k) = k_EOL - k. SOH and EOL use different reference capacities by design: because the Severson cycle-life label is defined relative to nominal capacity, EOL was kept consistent with that label, whereas SOH was normalised by the early-cycle median capacity to reduce the influence of cell-to-cell variation in initial capacity. RUL therefore qualifies a cell whenever its capacity reaches 0.88 Ah within the recorded window, which 128 of the 140 SOH cells satisfy."));

C.push(H1("4. Methodology"));
C.push(H2("4.1 Feature engineering from charge/discharge curves"));
C.push(P("For each cycle we extracted health indicators (HIs) from the available laboratory charge and discharge records, in three groups; several of these descriptors could in principle be estimated from sufficiently informative on-board voltage-current records, and we examine partial-cycle observation explicitly in Section 5.7; noisy-sensor and pack-level deployment are left to future work. The summary HIs (five) are charge time, internal resistance, and the average, maximum and minimum temperature. The discharge-voltage-curve shape features (six) are the fraction of capacity released once the cell voltage has fallen to fixed thresholds (3.3, 3.2, 3.1, 3.0 and 2.8 V for LFP), together with the median discharge voltage. Because these are normalised, they encode curve shape rather than absolute capacity and therefore avoid label leakage. The incremental-capacity (IC) features (four) were derived from the IC curve |dQ/dV|, obtained by numerical differentiation of Q(V) followed by Savitzky-Golay smoothing ([27]; window length 51 points on the 1000-point grid, polynomial order 3): the peak height, its voltage position, its full-width at half-maximum, and the IC area in the LFP plateau window. The IC peak is robust to the smoothing choice, with Spearman rank correlation above 0.99 across window lengths of 21 to 51 points and polynomial orders 2 to 3, and a per-sample coefficient of variation with a median below 1% (95th percentile 1.5%) (Supplementary Table S1). As Figure 2 shows for a representative cell, the IC peak falls and shifts as the cell ages, and the magnitude of the curve difference ΔQ(V) increases over ageing cycles, which motivates the variance feature."));
fig("fig2_ic_curves.png", "Figure 2. Feature definitions on a representative cell, with curve families coloured continuously by cycle number (colour bars). (a) The IC |dQ/dV| family drops and shifts with ageing; annotations mark the four IC features (peak height, peak position, FWHM, and the shaded IC-area window). (b) The ΔQ(V) = Q_cyc - Q_early family grows in magnitude with ageing, motivating the var(ΔQ) feature. (c) Curve-shape features: capacity fractions at the five voltage thresholds (dashed guides) and the median discharge voltage (red marker).", 620, 196).forEach(x => C.push(x));
C.push(H2("4.2 SOH estimation models"));
C.push(P("SOH was regressed from the 15 HI features using three representative algorithms, implemented in scikit-learn [28]: ridge regression (regularisation α = 1), support-vector regression with an RBF kernel ([29]; C = 10, ε = 0.005, γ set by the scale heuristic), and a random forest ([30]; 300 trees, minimum two samples per leaf). To prevent same-cell leakage, all splits were made at the cell level, so cells in the test set never appear in training; for the ablation we report the mean and standard deviation over five random cell-level splits. Features were standardised on the training partition only. Each cycle was treated as an equally weighted sample, so longer-lived cells contribute proportionally more cycle-level points; we did not reweight by cell and note this as a possible source of bias toward long-lived cells."));
C.push(H2("4.3 Active learning for sample-efficient model building"));
C.push(P("We tested whether active learning reduces the number of cells that must be cycled. Model building was cast as pool-based active learning on the homogeneous batches 1 and 2 (94 cells, cycle-life target). From a random labelled seed of six cells, a random-forest surrogate was fitted; the unlabelled pool was ranked by predictive uncertainty, defined as the standard deviation across the forest trees; and the three most uncertain cells were revealed per acquisition round. Performance was evaluated before each acquisition, at labelling budgets from 6 to 39 cells (eleven acquisitions). We compared this strategy against random sampling at equal labelling budget, repeated the whole procedure over twelve random seeds, and report the mean and standard deviation of the test R² at each budget (Figure 5)."));
C.push(H2("4.4 Symbolic regression for interpretable degradation laws"));
C.push(P("To obtain a human-readable degradation law, we applied genetic-programming symbolic regression (gplearn; [31]) to predict log-cycle-life from the engineered features, with the function set {+, -, ×, ÷, √, log, inverse} and a parsimony penalty; log denotes the natural logarithm. The evolved program was converted to a closed-form expression. Because genetic programming recovers structure but not well-calibrated coefficients, we applied a one-parameter linear calibration of the evolved expression on the training set, and all parity plots are shown in cycle-life units unless otherwise stated."));
C.push(H2("4.5 Conformal prediction intervals"));
C.push(P("Point predictions were augmented with prediction intervals through split-conformal prediction [23,24]. The training cells were partitioned, at the cell level, into a proper-training set and a calibration set. The model was fitted on the former, and absolute residuals r = |y − ŷ| were computed on the calibration cells. Let k = ⌈(n_cal + 1)(1 − α)⌉, where n_cal is the number of calibration residuals; q is the k-th smallest residual, capped at the largest residual when k exceeds n_cal, and the interval is ŷ ± q. This gives marginal coverage at level 1 − α under exchangeability of the calibration and test points. Because cycle-level samples from the same cell are strongly correlated, we calibrated and tested at the cell level and report empirical coverage as the operative quantity, rather than claiming a strict per-prediction guarantee. For comparison, we also report a heuristic tree-quantile interval spanning the 5th to 95th percentile of the random-forest tree predictions."));
C.push(H2("4.6 RUL prediction"));
C.push(P("RUL was regressed from the HI features following an SOH-to-ageing-model-to-RUL pathway, and we evaluated three input settings that differ only in how the SOH input is obtained: (i) curve features only, requiring no capacity label at inference; (ii) an end-to-end setting in which the SOH input is an out-of-sample prediction from a SOH model trained only on the training cells; and (iii) an oracle, SOH-assisted setting in which the SOH input is the measured, capacity-derived value. Unless stated otherwise, deployable performance refers to settings (i) and (ii), which use no measured capacity at inference; setting (iii) is reported only as an upper bound that quantifies the optimism introduced by a perfect SOH label. The main RUL figure (Figure 4) therefore shows the end-to-end setting (ii), with the oracle overlaid for comparison. Cell-level splitting and conformal intervals were applied as above."));

C.push(H1("5. Results"));
C.push(H2("5.1 SOH estimation and feature ablation"));
C.push(P("On one held-out cell-level split, used for visualisation, the random forest achieved the best accuracy (RMSPE 1.04%, mean absolute error (MAE) 0.59% SOH, R² = 0.964), ahead of SVR (1.28%, R² = 0.944) and ridge regression (2.35%, R² = 0.823) (Table 3; Figure 3a,c,d). Across five random cell-level splits, the same full 15-feature random forest achieved R² = 0.933 ± 0.03; the difference from the single-split value reflects split-to-split variation, not a different model. A feature ablation over these five splits (Table 4) showed a clear progression: summary HIs alone reached R² = 0.654 ± 0.08; adding the discharge-curve shape features raised this to R² = 0.919 ± 0.04; and adding the IC features gave the full model at R² = 0.933 ± 0.03. The single IC peak-height feature accounted for 0.88 of the random-forest impurity importance, the largest of any feature on this dataset. A permutation-importance analysis, measured as the decrease in test R² after permuting each feature and averaged over five cell-level splits, confirmed this ranking: permuting the IC peak feature reduced the test R² by 0.94, far more than any other feature, and it retained the largest importance under both impurity and permutation measures (Supplementary Figure S1); the per-batch correlation structure of all 15 HIs with SOH is mapped in Supplementary Figure S3. This identifies incremental-capacity analysis as a strong and physically interpretable health indicator. For comparison, a multilayer perceptron baseline was unstable under cell-level splitting (R² = -0.5 ± 1.2 over five splits). We read this as a limitation of the present cell count rather than evidence that deep models are inherently unsuitable: no extensive regularisation tuning was attempted, and recurrent and Transformer models operating on raw cycle sequences [32,33] remain a systematic comparison for future work (Section 6)."));
